import{_ as t,a as o,b as a,c as d,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as i}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as c,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/ocr.md","filePath":"my/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"my/Other/ocr.md"};function u(g,e,h,m,b,y){return n(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR က images, scans, document screenshots ထဲက text ကို extract လုပ်ပါတယ်။</p><p>recognition ပြီးနောက် result ကို copy လုပ်နိုင်ပြီး <code>Markdown</code>, <code>PDF</code>, <code>Word</code> အဖြစ် export လုပ်နိုင်ပါတယ်။ formats အများကြီးကို package တစ်ခုအဖြစ် download လုပ်နိုင်ပါတယ်။</p><h2 id="ocr-က-ဘာလုပ်နိုင်လဲ" tabindex="-1">OCR က ဘာလုပ်နိုင်လဲ <a class="header-anchor" href="#ocr-က-ဘာလုပ်နိုင်လဲ" aria-label="Permalink to &quot;OCR က ဘာလုပ်နိုင်လဲ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>images, screenshots, scans ထဲက text ကို extract လုပ်သည်။</td></tr><tr><td>Document layout recognition</td><td>tables, formulas, stamps, mixed text-image layouts အတွက်ပိုသင့်တော်သည်။</td></tr><tr><td>Multiple services</td><td>Baidu PaddleOCR, Microsoft Azure Vision, Google Vision support လုပ်သည်။</td></tr><tr><td>Copy results</td><td>processing ပြီးနောက် recognized text copy လုပ်နိုင်သည်။</td></tr><tr><td>Export files</td><td><code>Markdown</code>, <code>PDF</code>, <code>Word</code> export လုပ်နိုင်သည်။</td></tr><tr><td>Batch packaging</td><td>files အများကြီး recognize ပြီးနောက် results ကို package အဖြစ် download လုပ်နိုင်သည်။</td></tr></tbody></table><h2 id="ocr-services-ကိုအရင်-configure-လုပ်ပါ" tabindex="-1">OCR Services ကိုအရင် Configure လုပ်ပါ <a class="header-anchor" href="#ocr-services-ကိုအရင်-configure-လုပ်ပါ" aria-label="Permalink to &quot;OCR Services ကိုအရင် Configure လုပ်ပါ&quot;">​</a></h2><p>ဖွင့်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="IP geolocation and OCR" loading="lazy"></p><p>သုံးချင်တဲ့ services အတွက် credentials ဖြည့်ပါ:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>ပထမဦးဆုံးအကြံပြုသောရွေးချယ်မှု။ documents, images, tables, mixed layouts အတွက်ကောင်းသည်။</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> နဲ့ <code>Azure Vision API Key</code></td><td>Microsoft cloud services သုံးပြီးသားဖြစ်လျှင်အသုံးဝင်သည်။</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>။ Service account <code>JSON</code> ကို quota query အတွက်သာသုံးသည်။</td><td>Google Cloud services သုံးလျှင်အသုံးဝင်သည်။</td></tr></tbody></table><p>credentials ဖြည့်ပြီးနောက် save လုပ်ပါ။</p><p>initial testing အတွက် service တစ်ခုပဲ configure လုပ်ရင်လုံလောက်ပါတယ်။ သုံးခုလုံးမလိုပါ။</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup မှာ အပိုင်းနှစ်ပိုင်းရှိပါတယ်:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>OCR သုံးရန်</td><td><code>Cloud Vision API</code> enable လုပ်ပြီး <code>API Key</code> ဖန်တီးပါ။</td></tr><tr><td>usage query လုပ်ရန်</td><td>service account ဖန်တီးပါ၊ <code>Monitoring Viewer</code> grant လုပ်ပါ၊ service account <code>JSON</code> download လုပ်ပါ။</td></tr></tbody></table><p><img src="'+i+'" alt="Google API key and service account" loading="lazy"></p><h3 id="google-ကို-ocr-အတွက်သုံးခြင်း" tabindex="-1">Google ကို OCR အတွက်သုံးခြင်း <a class="header-anchor" href="#google-ကို-ocr-အတွက်သုံးခြင်း" aria-label="Permalink to &quot;Google ကို OCR အတွက်သုံးခြင်း&quot;">​</a></h3><ol><li>Google Cloud Console ကိုဖွင့်ပါ။</li><li><code>APIs &amp; Services</code> ကိုသွားပါ။</li><li><code>Library</code> ကိုဖွင့်ပြီး <code>Cloud Vision API</code> ရှာကာ enable လုပ်ပါ။</li><li><code>Credentials</code> ကိုပြန်သွားပါ။</li><li><code>API Key</code> ဖန်တီးပါ။</li><li>API Key ကိုဖွင့်ပြီး copy လုပ်ပါ။</li><li>ImgBed ထဲက <code>Google Vision API Key</code> မှာ paste လုပ်ပါ။</li><li>Save လုပ်ပါ။</li></ol><p>ပြီးရင် OCR dialog မှာ Google Vision ကိုရွေးနိုင်ပါပြီ။</p><h3 id="google-usage-query" tabindex="-1">Google Usage Query <a class="header-anchor" href="#google-usage-query" aria-label="Permalink to &quot;Google Usage Query&quot;">​</a></h3><p>Quota query က recognition အတွက် required မဟုတ်ပါ။</p><p>ပြီးခဲ့တဲ့ 30 days အတွင်း Google Vision calls ဘယ်လောက်သုံးထားလဲဆိုတာ rough count ပြတာပါ။</p><ol><li>Google Cloud Console မှာ <code>IAM &amp; Admin</code> ကိုဖွင့်ပါ။</li><li><code>Service Accounts</code> ကိုဖွင့်ပါ။</li><li>service account ဖန်တီးပါ၊ ဥပမာ <code>vision-monitor</code>။</li><li><code>Monitoring Viewer</code> role ပေးပါ။</li><li>service account details ကိုဖွင့်ပြီး key ဖန်တီးပါ။</li><li><code>JSON</code> ရွေးပါ။</li><li>generated JSON file ကို download လုပ်ပါ။</li><li>ImgBed ကိုပြန်သွားပြီး service account <code>JSON</code> အောက်မှာ import လုပ်ပါ (optional)။</li><li>import အောင်မြင်ပြီးနောက် quota query ကိုနှိပ်ပါ။</li></ol><p>import ပြီးနောက် ImgBed က service account ပိုင်တဲ့ project name ကိုပြပါမယ်။ usage query လုပ်တဲ့အခါ ImgBed က Google monitoring data ကိုဖတ်ပြီး ဒီလရဲ့ call count ကိုပြပါမယ်။</p><p>အတိုချုပ်:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>OCR recognition လုပ်သည်။</td></tr><tr><td>Service account <code>JSON</code></td><td>Google Vision calls သုံးစွဲမှု query လုပ်သည်။</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>service account ကို usage data ဖတ်ခွင့်ပေးသည်။</td></tr></tbody></table><h2 id="baidu-paddleocr-token-ရယူပါ" tabindex="-1">Baidu PaddleOCR Token ရယူပါ <a class="header-anchor" href="#baidu-paddleocr-token-ရယူပါ" aria-label="Permalink to &quot;Baidu PaddleOCR Token ရယူပါ&quot;">​</a></h2><p>Baidu PaddleOCR က access token လိုပါတယ်။</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Baidu PaddleOCR page မှာ <code>API</code> call window ဖွင့်ပါ၊ token ရယူရန် click လုပ်ပြီး copy လုပ်ပါ။</p><p>ImgBed ကိုပြန်သွားပြီး <code>PaddleOCR Token</code> ထဲ paste လုပ်ကာ save လုပ်ပါ။</p><h2 id="recognition-စတင်ခြင်း" tabindex="-1">Recognition စတင်ခြင်း <a class="header-anchor" href="#recognition-စတင်ခြင်း" aria-label="Permalink to &quot;Recognition စတင်ခြင်း&quot;">​</a></h2><p>File Management မှာ image သို့မဟုတ် document screenshot တစ်ခုရွေးပြီး <code>OCR</code> ကိုနှိပ်ပါ။</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>dialog မှာ recognition service နဲ့ model ရွေးပါ။</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>recommended default။ documents, tables, formulas, stamps, mixed layouts အတွက်ကောင်းသည်။</td></tr><tr><td><code>PP-OCRv5</code></td><td>simple images, ordinary text, lightweight recognition။</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>multilingual, complex images, chart-like content။</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>ပိုရှုပ်တဲ့ document pages နဲ့ layout recovery။</td></tr></tbody></table><p>မသေချာလျှင် <code>PP-StructureV3</code> နဲ့စပါ။</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>image လှည့်နေသို့မဟုတ် skewed ဖြစ်နေတဲ့အခါသုံးပါ။</td></tr><tr><td>Document flattening</td><td>photographed documents မှာ curvature သို့မဟုတ် tilt ရှိတဲ့အခါသုံးပါ။</td></tr><tr><td>Layout detection</td><td>headings, paragraphs, tables, image structure ကို preserve လုပ်ချင်တဲ့အခါသုံးပါ။</td></tr><tr><td>Chart recognition</td><td>image ထဲ charts သို့မဟုတ် complex structures ပါတဲ့အခါသုံးပါ။</td></tr><tr><td>Beautify <code>Markdown</code></td><td>exported Markdown ကိုပိုဖတ်လွယ်စေသည်။</td></tr></tbody></table><p>regular screenshots အတွက် options နည်းနည်းပဲထားပါ။ document scans အတွက် document-related options ပို enable လုပ်ပါ။</p><h2 id="results-ကြည့်ခြင်း" tabindex="-1">Results ကြည့်ခြင်း <a class="header-anchor" href="#results-ကြည့်ခြင်း" aria-label="Permalink to &quot;Results ကြည့်ခြင်း&quot;">​</a></h2><p>recognition ပြီးနောက် dialog မှာ result ပြပါမယ်။</p><p>တိုက်ရိုက် copy လုပ်နိုင်သလို export formats ရွေးနိုင်ပါတယ်။</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>document pages အတွက် exported <code>PDF</code> က page appearance ကိုထိန်းထားပြီး text ကို searchable ဖြစ်စေနိုင်ပါတယ်။ scans archive လုပ်ရန်နဲ့ နောက်ပိုင်း content ရှာရန်အသုံးဝင်ပါတယ်။</p><h2 id="export-format-ရွေးခြင်း" tabindex="-1">Export Format ရွေးခြင်း <a class="header-anchor" href="#export-format-ရွေးခြင်း" aria-label="Permalink to &quot;Export Format ရွေးခြင်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>notes, documentation systems, later editing။</td></tr><tr><td><code>PDF (.pdf)</code></td><td>page appearance နဲ့ scanned document results ထိန်းရန်။</td></tr><tr><td><code>Word (.docx)</code></td><td>layout editing ဆက်လုပ်ရန်၊ text modification, handoff။</td></tr><tr><td>Export all</td><td>multiple formats နဲ့ original image သိမ်းရန်၊ important archives အတွက်သင့်တော်သည်။</td></tr></tbody></table><p>text ပဲလိုလျှင် Markdown export လုပ်ပါ။</p><p>page appearance လိုလျှင် PDF သို့မဟုတ် Word သုံးပါ။</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>exported Word documents တွေကို office software နဲ့ဖွင့်ပြီး edit လုပ်နိုင်ပါတယ်။</p><p><img src="'+r+`" alt="Word result" loading="lazy"></p><p>documents အချို့မှာ Word output ထဲ recognized images, headings, paragraphs ပါနိုင်ပါတယ်။</p><p>recognition quality က original image clarity, model choice, document complexity အပေါ်မူတည်ပါတယ်။</p><h2 id="ocr-အတွက်သင့်တော်တဲ့-file-types" tabindex="-1">OCR အတွက်သင့်တော်တဲ့ File Types <a class="header-anchor" href="#ocr-အတွက်သင့်တော်တဲ့-file-types" aria-label="Permalink to &quot;OCR အတွက်သင့်တော်တဲ့ File Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>တိုက်ရိုက် recognize လုပ်ပါ။</td></tr><tr><td>Scans</td><td><code>PP-StructureV3</code> ကိုဦးစားပေးပါ။</td></tr><tr><td>Photographed documents</td><td>orientation correction နဲ့ document flattening enable လုပ်ပါ။</td></tr><tr><td>Tables, formulas, stamps</td><td>structured models ကိုဦးစားပေးပါ။</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> ကများသောအားဖြင့်လုံလောက်သည်။</td></tr></tbody></table><p>ပိုရှင်းတဲ့ images နဲ့ text ပိုတန်းတာက results ပိုကောင်းစေပါတယ်။</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>service token သို့မဟုတ် key save လုပ်ထားလားစစ်ပါ။</td></tr><tr><td>Recognition slow</td><td>complex documents နဲ့ large images တွေကအချိန်ပိုယူပါတယ်။</td></tr><tr><td>Table incomplete</td><td>structured model တစ်ခုစမ်းပါ။</td></tr><tr><td>Text mistakes</td><td>blur, glare, skew တို့က errors တိုးစေပါတယ်။ clearer image စမ်းပါ။</td></tr><tr><td>Word output မှာ images များ</td><td>structured models က recognized images အချို့ကို preserve လုပ်နိုင်ပါတယ်။ ဒါက normal ဖြစ်ပါတယ်။</td></tr></tbody></table><h3 id="google-quota-query-fail-ဖြစ်သည်" tabindex="-1">Google Quota Query Fail ဖြစ်သည် <a class="header-anchor" href="#google-quota-query-fail-ဖြစ်သည်" aria-label="Permalink to &quot;Google Quota Query Fail ဖြစ်သည်&quot;">​</a></h3><p>စစ်ပါ:</p><ol><li>Service account <code>JSON</code> import လုပ်ထားလား။</li><li>service account မှာ <code>Monitoring Viewer</code> role ရှိလား။</li><li>project အတွက် <code>Cloud Vision API</code> enabled ဖြစ်လား။</li></ol><p>OCR ပဲလိုပြီး usage query မလိုလျှင် service account JSON ကိုထားခဲ့ပြီး <code>Google Vision API Key</code> ပဲဖြည့်နိုင်ပါတယ်။</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; Other Settings ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; OCR service credentials ဖြည့်ပါ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; File Management ကိုပြန်သွားပါ</span></span>
<span class="line"><span>-&gt; file ရွေးပြီး OCR နှိပ်ပါ</span></span>
<span class="line"><span>-&gt; model ရွေးပါ</span></span>
<span class="line"><span>-&gt; recognition ပြီးအောင်စောင့်ပါ</span></span>
<span class="line"><span>-&gt; results copy လုပ်ပါ သို့မဟုတ် Markdown / PDF / Word export လုပ်ပါ</span></span></code></pre></div>`,67)])])}const v=c(p,[["render",u]]);export{C as __pageData,v as default};
